class Solution {
public:
    string minimizeStringValue(string s) {
        int count[26] = {0};
        int total_question_marks = 0;

        for (char c : s) {
            if (c == '?') {
                total_question_marks++;
            } else {
                count[c - 'a']++;
            }
        }

        string replacement;
        for (int i = 0; i < total_question_marks; i++) {
            int min_count = INT_MAX;
            char min_char = 'a';
            for (char c = 'a'; c <= 'z'; c++) {
                if (count[c - 'a'] < min_count) {
                    min_count = count[c - 'a'];
                    min_char = c;
                }
            }
            replacement += min_char;
            count[min_char - 'a']++;
        }

        sort(replacement.begin(), replacement.end());
        string result = s;
        int j = 0;
        for (int i = 0; i < s.length(); i++) {
            if (s[i] == '?') {
                result[i] = replacement[j++];
            }
        }

        return result;
    }
};
